var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"하아. 벌써 우리 둘만 남았네. 원본부터 조잡한 잡종들이라 어쩔 수 없나.","JPN":"あーあ、私たち2人だけしか残らなかったわね。そもそもオリジナルが粗末な雑種だから仕方ないか。","ENG":"Oh dear… It's just us two already? I guess these mutts never had a chance, coming from such lousy originals.","TWN":"哈，只剩我們兩個嗎？沒辦法，誰叫那群本來就是烏合之眾呢？"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_SWORD_HIT"},{"id":"L3_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"하지만 오히려 좋아. 이런 고조감 정말 오랜만이거든.","JPN":"でもこっちのほうがいい。こんな高調感は本当に久しぶり。","ENG":"But I actually prefer this development. It's been ages since I've felt this level of crescendo.","TWN":"不過這樣也好，好久沒有這麼興奮的感覺。"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"너는 어때, 호라이즌? 우리 둘이 자아내는 선율이 정말 짜릿하지 않니?","JPN":"ホライズン、あなたはどう？　私たち二人で奏でる旋律が実に刺激的だと思わない？","ENG":"How about you, Horizon? Isn't our dissonant harmony simply tantalizing?","TWN":"你呢，地平線？不覺得我們兩個譜出的旋律很激昂嗎？"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"뇌하수체가 상한 것 아닙니까. 병원에나 가 보십시오.","JPN":"脳下垂体の異常が考えられます。病院に行って受診してみてください。","ENG":"Such oxymoronic use of vocabulary may be a sign of a brain injury. I highly recommend you visit the nearest hospital.","TWN":"你的腦下垂體是不是有受損？要去看醫生嗎？"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"금속성 소음을 듣고 선율 운운하는 시점에서 판단력에 하자가 있다고 보입니다만.","JPN":"金属性の騒音を聴いて旋律云々と言う時点で判断力に欠陥があると思われますが。","ENG":"Besides, there's hardly anything harmonic about the noisy clashing of metal.","TWN":"雖然當你把那些金屬噪音當成旋律時，就表示你的判斷力已經出現瑕疵。"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_SWORD_HIT"},{"id":"L8_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"후훗. 틱틱거리는 것도 귀엽네. 내 동료들이 딱 너만큼만 앙칼졌어도 좋을 텐데.","JPN":"フフッ、つんつんしているのも可愛すぎるわ。私の仲間たちもあなたみたいに刺々しい感じだとよかったのに。","ENG":"Heh. I sure do love a good banter. I wish my colleagues were as feisty as you.","TWN":"呵呵～嘀嘀咕咕的樣子也很可愛呢～真希望我的同事們也跟你一樣毒舌～"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"동료 분들과 사이가 원만하지 않은 모양이군요. 그 성격으로 어련하겠습니까만.","JPN":"同僚の方との仲が円満ではないようですね。その性格だと仕方がありませんが。","ENG":"I take it that you do not get along with your colleagues. Hardly surprising, given your personality.","TWN":"你和同事的關係似乎不太好，不過以你的個性是完全可以理解的。"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"왜, 내 성격이 어때서?","JPN":"えー私の性格がなんだっていうのよ。","ENG":"What's wrong with my personality?","TWN":"為什麼？我的個性怎樣？"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"당신이 제 사무실을 습격한 휴먼들을 살해할 때의 눈빛. 기록에 남아 있습니다.","JPN":"あなたが私の事務所を襲撃したヒューマンたちを殺害した時の目つき。記録に残っています。","ENG":"The frenzied look in your eyes when you murdered the humans who raided my office… There remains a record of it in my log files.","TWN":"你殺害那些入侵我的辦公室的人類時，當時的那個眼神都有記錄下來。"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_SWORD_HIT"},{"id":"L13_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"응. 열정적이었지. 빗속에서 연주할 때는 나도 모르게 타오르거든.","JPN":"まあね。あの時はかなり情熱的だったわ。雨の中で演奏する時は、思わず熱くなってしまうから。","ENG":"Yeah. I sure got passionate back then. I tend to start playing molto appassionato when it's raining.","TWN":"嗯，眼神很炙熱吧？在雨中演奏時，我都會不自主地興奮起來。"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"휴먼들이 징그러운 벌레 보는 시선이더군요.","JPN":"ヒューマンたちを見るその目は、気持ち悪い虫を見る時の視線でした。","ENG":"I noticed you gazed upon the humans as they would a foul pest.","TWN":"那是人類看到噁心蟲子的眼神。"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"……호오.","JPN":"……へえ？","ENG":"Ooh…","TWN":"……喔。"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"증오가 아닌 단순한 혐오. 주거지에 침입한 해충을 밟아 죽일 기회만 노리는 시선.","JPN":"憎悪ではなく単なる嫌悪。住居に侵入した害虫を踏み潰すチャンスだけを狙う視線。","ENG":"It was not so much hatred as it was simple disgust. You had that revolting look in your eyes before stomping on a cockroach that violated your home.","TWN":"不是憎恨，而是單純的嫌惡。眼神就像是，要抓住機會踩死那些入侵住家的害蟲一樣。"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"리플레이서 융합체들을 처리했지만 침식파 반응은 사라지지 않았습니다.","JPN":"リプレイサー融合体たちを処理しましたが、侵食波反応は消えていません。","ENG":"The Replacer Hybriders have been neutralized, and yet the Corruption Ray signature remains.","TWN":"雖然已經處理掉克隆集團融合體，侵蝕波反應卻沒有消失。"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그리고 파형 분석 결과, 현재 이 상공에 유출된 침식파의 근원지는 당신입니다.","JPN":"そして波形分析の結果、現在この上空に流出している侵食波の源はあなたです。","ENG":"Analysis suggests that you are the source of the Corruption Ray radiation in this area.","TWN":"而且波形分析結果，現在流露至上空的侵蝕坡源頭就是你。"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"가만히 이면세계에 있을 것이지, 왜 현실세계로 기어나왔습니까. 침식체.","JPN":"大人しく裏世界にいればいいのに、なぜ現実世界に出てきたのですか、侵食体。","ENG":"Why did you have to crawl out to the Normalside instead of staying put in the Counterside? You Corrupted Object.","TWN":"怎麼不乖乖待在異界，為什麼要爬到現世來呢，侵蝕體？"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"윽……?!","JPN":"うっ……！？","ENG":"Ugh…?!","TWN":"唔……？！"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_SWORD_HIT"},{"id":"L24_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>경고. 사고회로의 과부하 감지. 침식파 차단 대책 강구.</color>","JPN":"<color=#ff3636>警告。思考回路の過負荷感知。侵食波遮断対策を講じます。</color>","ENG":"<color=#ff3636>Warning. Reasoning system overloaded. Seek immediate means of blocking the Corruption Ray.</color>","TWN":"<color=#ff3636>警告，感應到思考迴路超載。尋找侵蝕波阻斷對策。</color>"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"연주 중인데 이러쿵저러쿵 떠들다니 관람 매너가 부족하네, 호라이즌.","JPN":"演奏中なのに騒ぐなんて、観覧マナーがなってないわね、ホライズン。","ENG":"It's not very polite to chatter while the concert's still ongoing, Horizon.","TWN":"地平線，人家正在演奏，你在那邊嘰嘰喳喳的，有沒有禮貌？"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"<color=#ffd34c>우리</color>를 다른 짐승들과 싸잡아 취급하지 말아 주면 좋겠어. 벌레들이 만든 장난감 주제에.","JPN":"<color=#ffd34c>私たち</color>を他の獣どもと同じ扱いしないでちょうだい。虫けらどもが作ったオモチャの分際で。","ENG":"I really wish you wouldn't treat <color=#ffd34c>us</color> like the other critters. You're nothing but a toy those maggots created, after all.","TWN":"請不要把<color=#ffd34c>我們</color>和其他禽獸混為一談一談。更合況你還是那些蟲子所造的。"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"후후훗. 갑자기 움직임이 둔해지네. 왜 그러실까.","JPN":"フフッ。急に動きが鈍くなったわね。どうしたのかしら。","ENG":"Heh heh heh. I've noticed a sudden ritardando in your tempo. I wonder why that is?","TWN":"呵呵呵～你的行動怎麼突然變得那麼遲緩？是怎麼了嗎？"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_SWORD_HIT"},{"id":"L33_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"……제 회로에, 무슨 짓을 한 겁니까?","JPN":"……私の回路に、何をしたのですか？","ENG":"…What have you done… to my circuitry?","TWN":"……你對我的迴路做了什麼？"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"별거 아냐. 내 침식파를 음색에 실어서 흩뿌려 줬지.","JPN":"大したことないわ。私の侵食波を音色に乗せて撒いてあげたの。","ENG":"It’s not much, really. I simply scattered my C-Ray on a few notes.","TWN":"沒做什麼～不過就是將我的侵蝕波加到音色裡散播出去。"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"네 프레임을 부수는 건 쉽지 않아도, 그 저열한 성능의 인공지능은 얘기가 다르거든.","JPN":"あなたのフレームを壊すのは簡単じゃなくても、その低劣な人工知能は別よ。","ENG":"Breaking your frame may not be easy, but your inferior A.I. is a different story altogether.","TWN":"要破壞你的軀殼雖然不容易，但那個性能低劣的人工智慧可就不見得囉～"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"강인공지능은 정보 오염에 내성이 있다고 너무 자만한 거 아냐?","JPN":"強人工知能が情報汚染に耐性があるからって、うぬぼれすぎたんじゃない？","ENG":"Sure, Strong A.I.s are immune to data corruption… but you let that get to your head.","TWN":"就算高度人工智慧能夠抵抗情報污染，但你也未免太有自信了吧？"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"그렇다고 너무 무서워하지 마. 사고회로가 망가져 버려도 상냥하게 대해 줄게.","JPN":"でもあまり怖がらないで。思考回路が壊れてしまっても優しくしてあげるから。","ENG":"Don't be scared though. I'll be gentle with you even if your reasoning circuitry gets fried.","TWN":"不過你也不用太害怕，就算思考迴路壞掉，我也會友善對待你的。"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"우선은…… 그렇지, 윌버한테 사죄하라고 할까? 네가 무슨 표정을 지을지 궁금해지는데?","JPN":"まずは……そうね、ウィルバーに謝罪しなさいとでも\\n命令しようかしら？　あなたがどんな表情をするか楽しみだわ。","ENG":"For starters… Oh, I know. How about I make you apologize to Wilbur? I can't wait to see the look on your face!","TWN":"首先是……對了，要叫韋爾伯道歉嗎？真好奇你會是什麼表情？"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"당신의 역겨운 취향에 놀아나고 싶지는 않군요. 거부하겠습니다.","JPN":"あなたの気持ち悪い趣味に翻弄されたくはありません。拒否します。","ENG":"I'd rather not satiate your perverse fetish. I must decline.","TWN":"我沒有要附和你那奇怪興趣的意思，我拒絕回應。"},"stage":{"bg":"ROOFTOP","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>잔여 동력 3%. 출력폭 상승.</color>","JPN":"<color=#ff3636>残余エネルギー3％。出力幅上昇。</color>","ENG":"<color=#ff3636>Current remaining power is at 3%. Increasing output.</color>","TWN":"<color=#ff3636>剩餘動能3%。功率值增加。</color>"},"stage":{"bg":"ROOFTOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_SYS_START1"},{"id":"L43_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"무대 없이도 그렇게 잘난 듯이 활개칠 수 있는지, 시험해 드리죠.","JPN":"舞台そのものがなくてもそんな風に振る舞うことができるのか、試してみましょう。","ENG":"Let's see if you can still fiddle around like that without your stage.","TWN":"我們就來實驗看看，在沒有舞台的情況下，你的氣焰還能這麼囂張嗎？"},"stage":{"bg":"ROOFTOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"응? 너 설마……!","JPN":"うん？　あなた、まさか……！","ENG":"Huh? No… You wouldn't dare!","TWN":"嗯？你該不會是要……！"},"stage":{"bg":"ROOFTOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"치잇! 흥 깨지게 하네!!","JPN":"ちっ！　せっかく楽しんでいたのに！","ENG":"Ugh! Why you gotta be such a wet blanket?!","TWN":"嗟！哼！真掃興！！"},"stage":{"bg":"ROOFTOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"WILBURLOVER_NPC_NULL_NULL","text":{"KOREA":"꺄아아아악!","JPN":"きゃあああっ！","ENG":"Eeeeek!!","TWN":"啊啊啊啊！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"뭐, 뭐냐?! 뭐가 어떻게 된 거야! 어서 상황을 보고해!","JPN":"な、何だ？　何がどうなってんだ！　早く状況を報告しろ！","ENG":"W-what's going on?! What happened?! I want a SITREP, now!","TWN":"怎…怎麼了？！現在是怎麼回事！立刻回報狀況！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WILBURLOVER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"BOSS_HORIZON_NULL_NULL","text":{"KOREA":"저, 적이 방출한 에너지 탓입니다!","JPN":"て、敵が放出したエネルギーのせいです！","ENG":"T-the enemy emitted a powerful energy!","TWN":"都是因為敵人釋放的能量！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOSS_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L3_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"뭘 방출해? 에너지? 그 사채꾼이?","JPN":"何を放出した？　エネルギー？　あの闇金野郎が？","ENG":"Emitted what? Energy? From the loan shark?","TWN":"她釋放什麼？能量？那個放高利貸的？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"BOSS_HORIZON_NULL_NULL","text":{"KOREA":"네. 관측 상으로는 미상의 에너지로 선체를 공격하려고 했던 것 같습니다.","JPN":"はい。観測上は未詳のエネルギーで、船体を攻撃しようとしていたようです。","ENG":"Yes. Based on what we could observe, it seems she was trying to attack the ship with an unknown energy.","TWN":"是的，根據我們觀察到的，剛剛不知名的能量似乎企圖攻擊船身。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_HATE"},"C":null,"R":{"char_id":"BOSS_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"BOSS_HORIZON_NULL_NULL","text":{"KOREA":"경호실장님이 한 발 앞서 바다로 떨어뜨리지 않았더라면…….","JPN":"警護室長が一足先に海に落とさなかったら……","ENG":"If Ms. Shena hadn't plunged the hostile into the sea first…","TWN":"要不是護衛室長早一步將她擊落海裡……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_HATE"},"C":null,"R":{"char_id":"BOSS_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"뭐가 다행이라고 지껄여! 그러기 전에 폐품으로 만들었어야지!","JPN":"何を安心している！　そんな状況になる前に始末するべきだろ！","ENG":"Shena hasn't done jack! She should have crushed that brat before it came to this!","TWN":"你在說什麼鬼話？應該在那之前就先讓她報廢掉吧！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BOSS_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"셰나! 응답해!","JPN":"シェナ！　応答せよ！","ENG":"Shena! Get in here!","TWN":"世娜！回答我！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"어째서 끝장내지 않은 거냐! 바다에 떨어뜨리는 게 아니라 내 눈앞에서 확실하게 죽여 버렸어야지!","JPN":"なんでちゃんと仕留めなかったんだ！　海に落とすんじゃなくて、僕の目の前で確実に殺すべきだろ！","ENG":"Why haven't you finished her off?! You should have killed her right in front of my eyes, not dropped her into the ocean!","TWN":"怎麼到現在還沒處理好！你應該要在我面前殺掉她，而不是只是擊落海裡吧！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L14_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"너무 호들갑 떨지 말아 줬으면 좋겠는데, 대표님.","JPN":"あまり騒がないでもらいたいんだけど、代表。","ENG":"I wish you'd stop making such a big fuss, boss.","TWN":"我說代表，你可以不要只會放馬後炮嗎？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"호들갑? 나는 지금 네 안이한 대응을 지적하고 있는 거다! 진지하게 들어!","JPN":"騒ぐ？　僕は今お前の安易な対応を指摘しているんだ！　真面目に聞け！","ENG":"Fuss? I'm critiquing your carelessness right now! I demand you take this seriously!","TWN":"馬後炮？我現在對你輕蔑的態度非常不滿！你給我認真點！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"그럼 그 지적은 헛발질이란 사실을 알려 줘야겠네.","JPN":"ならその指摘は間違ってるって事実を教えてあげないとね。","ENG":"Then I should let you know you can take your critique and shove it.","TWN":"那我跟你說，你對我的不滿根本就是子虛烏有。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"방금 걔가 쇠파이프를 내리쳤으면 함선이 추락해도 이상하지 않았어.","JPN":"あの子があのまま鉄パイプを叩き降ろしてたら、艦船が墜落してもおかしくなかったわ。","ENG":"If she had struck down with her pipe, this ship could have crashed.","TWN":"剛剛她那根鐵管打下來的話，艦船就算墜落也不奇怪。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L18_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"그럼 아마 지금쯤 난 대표님 시신 수습할 걱정이나 하고 있었을걸?","JPN":"そうなったら、今頃私は代表の死体をどうやって収拾しようか迷っていたと思うわよ？","ENG":"Instead of listening to you nag, I'd be busy putting your tattered body back together.","TWN":"墜落的話，那我現在應該正苦惱著，要去哪打撈你的屍體好嗎？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"빌어먹을……! 또 변명! 할 줄 아는 건 변명뿐이지!","JPN":"くそ……！　また言い訳か！　お前はいつも言い訳ばかりだな！","ENG":"Damn it…! Excuses, excuses! All you do is make excuses!","TWN":"該死……！又給我頂嘴！你除了頂嘴還會什麼！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"WILBUR_NPC_NULL_MASKED","text":{"KOREA":"함교, 가까운 지사에 수색대를 파견하라고 해라! 우리는 본사로 간다!","JPN":"艦橋、近くの支社に捜索隊の派遣を要請しろ！　我々は本社に向かう！","ENG":"Bridge, tell the nearest branch to deploy a search party! And take us to HQ right away!","TWN":"艦橋，叫最近的分公司派遣搜查隊！我們移動去總公司！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WILBUR_NPC_NULL_MASKED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"BOSS_HORIZON_NULL_NULL","text":{"KOREA":"아, 알겠습니다! 대표님!","JPN":"しょ、承知しました、代表！","ENG":"R-roger that, boss!","TWN":"喔，是，代表！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOSS_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"흐음……♪ 흠흐흠……♬","JPN":"ふーん……♪　ふんふん……♬","ENG":"Ladeedah…♪ Tralala…♬","TWN":"拉拉……♪ 拉拉拉……♬"},"stage":{"bg":"ROOFTOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"두 번 기회는 없을 거야, 호라이즌.","JPN":"二度目のチャンスはないわ、ホライズン。","ENG":"You won't get a second chance next time, Horizon.","TWN":"地平線，沒有下次了。"},"stage":{"bg":"ROOFTOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"다음에도 이렇게 맥빠지는 합주로 끝나면 용서 안 해.","JPN":"次もこんなつまらない合奏で終わったら許さないから。","ENG":"I won't put up with such half-assed ensemble performance again.","TWN":"你下次再讓我掃興的話，我可不會這麼輕易就放過你。"},"stage":{"bg":"ROOFTOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"후훗, 웬일이야. 반가운 연락이 다 오네.","JPN":"フフッ、どうしたのかしら。嬉しい連絡が来たわね。","ENG":"Oh, look who it is. Just the person I've been dying to hear from.","TWN":"呵呵～這是怎麼回事，竟然自己打給我～"},"stage":{"bg":"ROOFTOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L30_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"네, 교수님? 무슨 일이야?","JPN":"はい、教授？　どうしたの？","ENG":"Hi, Professor! What's up?","TWN":"喂，教授？什麼事？"},"stage":{"bg":"ROOFTOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};